#include "littlefs_storage.h"
#include <LittleFS.h>
void littlefs_setup(){if(!LittleFS.begin(true)){Serial.println("[lfs] Fail!");return;}Serial.printf("[lfs] OK %luKB\n",(unsigned long)LittleFS.totalBytes()/1024);}
bool littlefs_write(const char*p,const char*d){File f=LittleFS.open(p,"w");if(!f)return false;f.print(d);f.close();return true;}
String littlefs_read(const char*p){File f=LittleFS.open(p,"r");if(!f)return"";String s=f.readString();f.close();return s;}
bool littlefs_exists(const char*p){return LittleFS.exists(p);}
void littlefs_remove(const char*p){LittleFS.remove(p);}
